import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    """
    # Mapping of AST operator nodes to actual Python functions
    _BIN_OPS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    _UNARY_OPS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        """Recursively evaluate an AST node."""
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")

        if isinstance(node, ast.Num):  # For older Python versions
            return node.n

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in _BIN_OPS:
                return _BIN_OPS[op_type](left, right)
            raise ValueError("Unsupported binary operator")

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in _UNARY_OPS:
                return _UNARY_OPS[op_type](operand)
            raise ValueError("Unsupported unary operator")

        if isinstance(node, ast.Paren):
            return _eval(node.value)

        # Disallow any other node types (e.g., calls, attributes, etc.)
        raise ValueError("Unsupported expression element")

    try:
        # Parse the expression safely in 'eval' mode
        parsed = ast.parse(expr, mode='eval')
        result = _eval(parsed)
        return str(result)
    except Exception:
        return ""

import os
import yaml

def yaml_load(filename):
    """
    Open the given file, safely load its YAML contents, and return the resulting data.
    """
    if not isinstance(filename, (str, bytes, os.PathLike)):
        raise TypeError("filename must be a path-like object")
    with open(filename, "r", encoding="utf-8") as f:
        return yaml.safe_load(f)

import xml.etree.ElementTree as ET

def parse_xml(xml_string):
    """
    Parse xml_string and return the root element of the XML document.
    """
    if not isinstance(xml_string, (str, bytes)):
        raise TypeError("xml_string must be a string or bytes")
    try:
        root = ET.fromstring(xml_string)
    except ET.ParseError as exc:
        raise ValueError(f"Invalid XML: {exc}") from None
    return root

