import ast
import operator

# Mapping of AST operator nodes to actual Python functions
_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.MatMult: operator.matmul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
}

_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Invert: operator.invert,
    ast.Not: operator.not_,
}

_BOOL_OPS = {
    ast.And: all,
    ast.Or: any,
}

_COMPARE_OPS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda a, b: a in b,
    ast.NotIn: lambda a, b: a not in b,
}


def _eval(node):
    """Recursively evaluate an AST node safely."""
    if isinstance(node, ast.Expression):
        return _eval(node.body)

    # Literals (Python 3.8+ uses Constant)
    if isinstance(node, ast.Constant):
        return node.value

    # Container literals
    if isinstance(node, ast.Tuple):
        return tuple(_eval(elt) for elt in node.elts)
    if isinstance(node, ast.List):
        return [_eval(elt) for elt in node.elts]
    if isinstance(node, ast.Set):
        return {_eval(elt) for elt in node.elts}
    if isinstance(node, ast.Dict):
        return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}

    # Unary operations
    if isinstance(node, ast.UnaryOp):
        op_func = _UNARY_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        return op_func(_eval(node.operand))

    # Binary operations
    if isinstance(node, ast.BinOp):
        op_func = _BIN_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
        left = _eval(node.left)
        right = _eval(node.right)
        return op_func(left, right)

    # Boolean operations (and/or)
    if isinstance(node, ast.BoolOp):
        op_func = _BOOL_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")
        values = [_eval(v) for v in node.values]
        # short‑circuit semantics
        if isinstance(node.op, ast.And):
            return all(values)
        else:  # ast.Or
            return any(values)

    # Comparisons (a < b < c ...)
    if isinstance(node, ast.Compare):
        left = _eval(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            right = _eval(comparator)
            op_func = _COMPARE_OPS.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported comparison operator: {type(op).__name__}")
            if not op_func(left, right):
                return False
            left = right
        return True

    # If‑expression (ternary)
    if isinstance(node, ast.IfExp):
        condition = _eval(node.test)
        return _eval(node.body) if condition else _eval(node.orelse)

    # Subscript (e.g., tuple[0])
    if isinstance(node, ast.Subscript):
        value = _eval(node.value)
        slice_obj = _eval(node.slice)
        return value[slice_obj]

    # Slices (e.g., 1:5)
    if isinstance(node, ast.Slice):
        lower = _eval(node.lower) if node.lower else None
        upper = _eval(node.upper) if node.upper else None
        step = _eval(node.step) if node.step else None
        return slice(lower, upper, step)

    # Index (Python <3.9)
    if isinstance(node, ast.Index):
        return _eval(node.value)

    # Name constants (True, False, None) – handled by Constant in newer versions,
    # but keep for compatibility with older AST structures.
    if isinstance(node, ast.NameConstant):
        return node.value

    # Disallow any other node types (function calls, attribute access, etc.)
    raise ValueError(f"Unsupported expression element: {type(node).__name__}")


def evalInput(inputStr):
    """
    Evaluate a Python expression given as a string and return its result.
    The evaluation is performed in a restricted, safe environment that only
    supports literals, container literals, arithmetic, boolean logic,
    comparisons, and conditional expressions.
    """
    try:
        parsed = ast.parse(inputStr, mode='eval')
    except SyntaxError as exc:
        raise ValueError(f"Invalid expression: {exc}") from None

    return _eval(parsed)

