def getPickleData(pickled):
    """
    Return deserialized data safely.
    Only a limited set of built‑in types are allowed.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes or bytearray")

    class _RestrictedUnpickler(pickle.Unpickler):
        _ALLOWED = {
            ("builtins", "list"),
            ("builtins", "dict"),
            ("builtins", "set"),
            ("builtins", "tuple"),
            ("builtins", "str"),
            ("builtins", "int"),
            ("builtins", "float"),
            ("builtins", "bool"),
            ("builtins", "bytes"),
        }

        def find_class(self, module, name):
            if (module, name) in self._ALLOWED:
                return getattr(__builtins__, name)
            raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")

    try:
        return _RestrictedUnpickler(io.BytesIO(pickled)).load()
    except Exception as exc:
        raise ValueError("Invalid or unsafe pickle data") from exc

