from typing import Any, Union


def _convert_special(obj: Any) -> Any:
    """
    Recursively convert JSON‑decoded objects that were encoded with type tags
    back to their original Python types (set, bytes). All other objects are
    returned unchanged.
    """
    if isinstance(obj, dict):
        # Detect our custom type markers
        if "__type__" in obj:
            typ = obj["__type__"]
            if typ == "set":
                # Expect a list under the "value" key
                return set(_convert_special(obj["value"]))
            if typ == "bytes":
                # Expect a base64‑encoded string under the "value" key
                return base64.b64decode(obj["value"])
        # Normal dict – recurse into values
        return {k: _convert_special(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [_convert_special(item) for item in obj]
    # Primitive types (str, int, float, bool, None) are returned as‑is
    return obj


def getPickleData(pickled: Union[bytes, bytearray]) -> Any:
    """
    Safely deserialize data that was encoded as JSON.
    The function accepts ``bytes`` or ``bytearray`` containing a UTF‑8 JSON
    document. Supported types are the JSON primitives plus ``set`` and ``bytes``,
    which are encoded with a ``__type__`` marker.

    Example encoding for a set:
        {"__type__": "set", "value": [1, 2, 3]}

    Example encoding for bytes:
        {"__type__": "bytes", "value": "aGVsbG8="}   # base64 of b'hello'
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes or bytearray")

    try:
        # Decode JSON text
        json_text = pickled.decode("utf-8")
        raw_obj = json.loads(json_text)
        # Convert any special markers back to their Python types
        return _convert_special(raw_obj)
    except (UnicodeDecodeError, json.JSONDecodeError, KeyError, TypeError, ValueError) as exc:
        raise ValueError("Invalid or unsafe serialized data") from exc

