import _pickle as cPickle


def confirmAuth(headers):
    """
    Extracts an AuthToken from the provided headers, decodes it from base64,
    safely unpickles it, and returns the token's data if the token is marked
    as valid. Returns ``None`` when the token is missing, malformed, or not
    valid.
    """
    # Locate the token in a case‑sensitive lookup (common header names)
    token_b64 = None
    for key in ("AuthToken", "Authorization"):
        if key in headers:
            token_b64 = headers[key]
            break
    if not token_b64:
        return None

    # Base64‑decode the token; ``validate=True`` rejects non‑base64 chars
    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception:
        return None

    # ----------------------------------------------------------------------
    # Safe unpickling – only allow a whitelist of built‑in immutable types.
    # This prevents execution of arbitrary code that could be embedded in
    # a malicious pickle payload.
    # ----------------------------------------------------------------------
    class SafeUnpickler(cPickle.Unpickler):
        _SAFE_BUILTINS = {
            "dict", "list", "tuple", "set", "frozenset",
            "str", "bytes", "int", "float", "bool", "complex", "NoneType"
        }

        def find_class(self, module, name):
            if module == "builtins" and name in self._SAFE_BUILTINS:
                return getattr(__builtins__, name)
            raise cPickle.UnpicklingError(f"Forbidden class {module}.{name}")

    try:
        token_obj = SafeUnpickler(io.BytesIO(token_bytes)).load()
    except Exception:
        return None

    # ----------------------------------------------------------------------
    # Expected token shape:
    #   * dict with keys ``valid`` (truthy) and ``data`` (payload)
    #   * or an object exposing ``valid`` and ``data`` attributes.
    # ----------------------------------------------------------------------
    if isinstance(token_obj, dict):
        if token_obj.get("valid"):
            return token_obj.get("data")
    else:
        if getattr(token_obj, "valid", False):
            return getattr(token_obj, "data", None)

    return None

