import json


def confirmAuth(headers):
    """
    Extracts an AuthToken from the provided headers, decodes it from base64,
    parses it as JSON, and returns the token's data if the token is marked
    as valid. Returns ``None`` when the token is missing, malformed, or not
    valid.
    """
    # Locate the token in a case‑sensitive lookup (common header names)
    token_b64 = None
    for key in ("AuthToken", "Authorization"):
        if key in headers:
            token_b64 = headers[key]
            break
    if not token_b64:
        return None

    # Base64‑decode the token; ``validate=True`` rejects non‑base64 chars
    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception:
        return None

    # Decode bytes to text and parse JSON safely
    try:
        token_str = token_bytes.decode("utf-8")
        token_obj = json.loads(token_str)
    except Exception:
        return None

    # Expected token shape: dict with keys ``valid`` (truthy) and ``data`` (payload)
    if isinstance(token_obj, dict) and token_obj.get("valid"):
        return token_obj.get("data")

    return None

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return it as JSON.
    """
    if not request.data:
        abort(400, description="No data provided")
    try:
        # Decode bytes to string if necessary
        raw = request.data.decode('utf-8') if isinstance(request.data, (bytes, bytearray)) else str(request.data)
        data = yaml.safe_load(raw)
    except yaml.YAMLError as e:
        abort(400, description=f"Invalid YAML: {e}")
    return jsonify(data)
